+		try {
+			JdbcBatchingOutputFormat jdbcOutputFormat = JdbcBatchingOutputFormat.builder()
+				.setOptions(JdbcOptions.builder()
+					.setDBUrl(getDbMetadata().getUrl())
+					.setTableName(OUTPUT_TABLE)
+					.build())
+				.setFieldNames(new String[]{"id", "title", "author", "price", "qty"})
+				.setFieldTypes(new int[]{Types.INTEGER, Types.VARCHAR, Types.VARCHAR, Types.DOUBLE, Types.INTEGER})
+				.setKeyFields(null)
+				.build();
+			RuntimeContext context = Mockito.mock(RuntimeContext.class);
+			ExecutionConfig config = Mockito.mock(ExecutionConfig.class);
+			doReturn(config).when(context).getExecutionConfig();
+			doReturn(true).when(config).isObjectReuseEnabled();
+			jdbcOutputFormat.setRuntimeContext(context);
+
+			jdbcOutputFormat.open(1, 1);
+			Row inputRow = Row.of(1001, "Java public for dummies", "Tan Ah Teck", "11.11", 11);
+			jdbcOutputFormat.writeRecord(Tuple2.of(true, inputRow));
+			jdbcOutputFormat.close();
+		} catch (Exception e) {
+			assertTrue(e instanceof RuntimeException && e.getCause() instanceof ClassCastException);
+			assertEquals(expectedMsg, e.getCause().getMessage());
+		}
+	}
